    lookup = {}
    for proj in data['projects']:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (pname, fw['framework'], pkg['id'])
                lookup[key] = pkg['resolvedVersion']
    return lookup

bl = build_lookup(baseline)
af = build_lookup(after)

print('=== CHANGES (version aligned to highest) ===')
changes = []
for key in sorted(set(list(bl.keys()) + list(af.keys()))):
    bv = bl.get(key, 'ADDED')
    av = af.get(key, 'REMOVED')
    if bv != av:
        changes.append((key[0], key[1], key[2], bv, av))

if changes:
    for c in changes:
        print(f'  {c[0]} | {c[1]} | {c[2]} | {c[3]} -> {c[4]}')
else:
    print('  No unexpected changes')

print()
unchanged = sum(1 for k in bl if bl.get(k) == af.get(k))
print(f'=== UNCHANGED: {unchanged} package-framework entries resolve identically ===')
